{
  "permissions": {
    "allow": [
      "Bash(mkdir:*)",
      "Bash(npx prettier:*)",
      "Bash(npx eslint:*)",
      "Bash(npx tsc:*)",
      "Read(**)",
      "Write(**)",
      "Edit(**)",
      "Bash(git add:*)",
      "Bash(grep:*)"
    ],
    "deny": [
      "Read(.env)",
      "Read(../.env)"
    ],
    "ask": []
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "command",
            "command": "npx prettier --write \"$CLAUDE_FILE_PATH\" 2>/dev/null || true"
          },
          {
            "type": "command",
            "command": "git add --ignore-errors \"$CLAUDE_FILE_PATH\" 2>/dev/null || true"
          }
        ]
      }
    ]
  }
}
